class InputValidationError(Exception):
    """Raised when input validation fails."""
    pass


class KafkaAdminSecurityError(Exception):
    """Raised when security checks fail."""
    pass


def validate_topic_name(topic_name: str) -> str:
    """
    Validate a Kafka topic name against strict rules.
    Prevents injection and ensures compliance with Kafka naming conventions.
    """
    if not topic_name:
        raise InputValidationError("Topic name cannot be empty.")

    if len(topic_name) > MAX_TOPIC_NAME_LENGTH:
        raise InputValidationError(
            f"Topic name exceeds maximum length of {MAX_TOPIC_NAME_LENGTH} characters."
        )

    if not TOPIC_NAME_PATTERN.match(topic_name):
        raise InputValidationError(
            f"Topic name '{topic_name}' contains invalid characters. "
            "Only alphanumeric characters, '.', '_', and '-' are allowed."
        )

    # Kafka internal topics should not be managed by this tool
    if topic_name.startswith("__"):
        raise InputValidationError(
            "Cannot manage internal Kafka topics (starting with '__')."
        )

    if topic_name in (".", ".."):
        raise InputValidationError("Topic name cannot be '.' or '..'.")

    return topic_name


def validate_partitions(partitions: int) -> int:
    """Validate partition count is within acceptable range."""
    if not isinstance(partitions, int):
        raise InputValidationError("Partition count must be an integer.")
    if partitions < MIN_PARTITIONS or partitions > MAX_PARTITIONS:
        raise InputValidationError(
            f"Partition count must be between {MIN_PARTITIONS} and {MAX_PARTITIONS}."
        )
    return partitions


def validate_replication_factor(replication_factor: int) -> int:
    """Validate replication factor is within acceptable range."""
    if not isinstance(replication_factor, int):
        raise InputValidationError("Replication factor must be an integer.")
    if replication_factor < MIN_REPLICATION_FACTOR or replication_factor > MAX_REPLICATION_FACTOR:
        raise InputValidationError(
            f"Replication factor must be between {MIN_REPLICATION_FACTOR} and {MAX_REPLICATION_FACTOR}."
        )
    return replication_factor


def validate_topic_config(config: Dict[str, str]) -> Dict[str, str]:
    """
    Validate topic configuration against allowlist.
    Only permitted configuration keys with valid values are accepted.
    """
    validated = {}

    for key, value in config.items():
        # Check key is in allowlist
        if key not in ALLOWED_TOPIC_CONFIGS:
            raise InputValidationError(
                f"Configuration key '{key}' is not in the allowed configuration list. "
                f"Allowed keys: {sorted(ALLOWED_TOPIC_CONFIGS)}"
            )

        # Convert value to string and strip whitespace
        value = str(value).strip()

        if not value:
            raise InputValidationError(f"Configuration value for '{key}' cannot be empty.")

        # Validate against specific patterns if available
        if key in CONFIG_VALUE_VALIDATORS:
            if not CONFIG_VALUE_VALIDATORS[key].match(value):
                raise InputValidationError(
                    f"Invalid value '{value}' for configuration key '{key}'."
                )

        # Validate numeric values
        if key in NUMERIC_CONFIG_KEYS:
            try:
                numeric_val = int(value)
                if numeric_val < -1:  # -1 is valid for some configs (e.g., retention.bytes = unlimited)
                    raise InputValidationError(
                        f"Numeric value for '{key}' must be >= -1, got {numeric_val}."
                    )
            except ValueError:
                raise InputValidationError(
                    f"Configuration key '{key}' requires a numeric value, got '{value}'."
                )

        # Validate float values
        if key in FLOAT_CONFIG_KEYS:
            try:
                float_val = float(value)
                if float_val < 0.0 or float_val > 1.0:
                    raise InputValidationError(
                        f"Float value for '{key}' must be between 0.0 and 1.0, got {float_val}."
                    )
            except ValueError:
                raise InputValidationError(
                    f"Configuration key '{key}' requires a float value, got '{value}'."
                )

        validated[key] = value

    return validated


def validate_bootstrap_servers(servers: str) -> str:
    """Validate bootstrap servers string format."""
    if not servers:
        raise InputValidationError("Bootstrap servers cannot be empty.")

    # Basic validation: host:port pairs separated by commas
    server_pattern = re.compile(
        r'^[a-zA-Z0-9._\-]+(:\d{1,5})?'
        r'(,[a-zA-Z0-9._\-]+(:\d{1,5})?)*$'
    )

    if not server_pattern.match(servers):
        raise InputValidationError(
            "Bootstrap servers must be comma-separated host:port pairs."
        )

    # Validate port ranges
    for server in servers.split(","):
        parts = server.split(":")
        if len(parts) == 2:
            port = int(parts[1])
            if port < 1 or port > 65535:
                raise InputValidationError(
                    f"Invalid port number {port} in bootstrap server '{server}'."
                )

    return servers


def load_secrets_from_env() -> Dict[str, Optional[str]]:
    """
    Load sensitive configuration from environment variables.
    Never store secrets in plaintext files or command-line arguments.
    """
    secrets = {
        "sasl_username": os.environ.get("KAFKA_SASL_USERNAME"),
        "sasl_password": os.environ.get("KAFKA_SASL_PASSWORD"),
        "ssl_cafile": os.environ.get("KAFKA_SSL_CAFILE"),
        "ssl_certfile": os.environ.get("KAFKA_SSL_CERTFILE"),
        "ssl_keyfile": os.environ.get("KAFKA_SSL_KEYFILE"),
        "ssl_password": os.environ.get("KAFKA_SSL_KEY_PASSWORD"),
    }
    return secrets


def validate_file_path(file_path: Optional[str], description: str) -> Optional[str]:
    """Validate that a file path exists and is readable, with path traversal protection."""
    if file_path is None:
        return None

    path = Path(file_path).resolve()

    # Prevent path traversal - ensure the resolved path doesn't escape expected directories
    if ".." in Path(file_path).parts:
        raise KafkaAdminSecurityError(
            f"Path traversal detected in {description}: '{file_path}'"
        )

    if not path.exists():
        raise KafkaAdminSecurityError(
            f"{description} file does not exist: '{path}'"
        )

    if not path.is_file():
        raise KafkaAdminSecurityError(
            f"{description} path is not a file: '{path}'"
        )

    if not os.access(path, os.R_OK):
        raise KafkaAdminSecurityError(
            f"{description} file is not readable: '{path}'"
        )

    return str(path)


def create_admin_client(
    bootstrap_servers: str,
    security_protocol: str = "SASL_SSL",
    sasl_mechanism: str = "PLAIN",
) -> KafkaAdminClient:
    """
    Create a KafkaAdminClient with secure configuration.
    Uses SSL/TLS and SASL authentication by default.
    """
    validated_servers = validate_bootstrap_servers(bootstrap_servers)
    secrets = load_secrets_from_env()

    # Validate security protocol
    allowed_protocols = {"SASL_SSL", "SSL", "SASL_PLAINTEXT", "PLAINTEXT"}
    if security_protocol not in allowed_protocols:
        raise InputValidationError(
            f"Invalid security protocol '{security_protocol}'. "
            f"Allowed: {allowed_protocols}"
        )

    # Warn if using insecure protocols
    if security_protocol in ("PLAINTEXT", "SASL_PLAINTEXT"):
        logger.warning(
            "WARNING: Using insecure protocol '%s'. "
            "This should only be used in development environments.",
            security_protocol,
        )

    # Validate SASL mechanism
    allowed_mechanisms = {"PLAIN", "SCRAM-SHA-256", "SCRAM-SHA-512", "GSSAPI", "OAUTHBEARER"}
    if sasl_mechanism not in allowed_mechanisms:
        raise InputValidationError(
            f"Invalid SASL mechanism '{sasl_mechanism}'. "
            f"Allowed: {allowed_mechanisms}"
        )

    client_config: Dict[str, Any] = {
        "bootstrap_servers": validated_servers,
        "security_protocol": security_protocol,
        "request_timeout_ms": 30000,
        "connections_max_idle_ms": 60000,
    }

    # Configure SASL if needed
    if "SASL" in security_protocol:
        if not secrets["sasl_username"] or not secrets["sasl_password"]:
            raise KafkaAdminSecurityError(
                "SASL authentication requires KAFKA_SASL_USERNAME and "
                "KAFKA_SASL_PASSWORD environment variables to be set."
            )
        client_config["sasl_mechanism"] = sasl_mechanism
        client_config["sasl_plain_username"] = secrets["sasl_username"]
        client_config["sasl_plain_password"] = secrets["sasl_password"]

    # Configure SSL if needed
    if "SSL" in security_protocol:
        ssl_cafile = validate_file_path(secrets["ssl_cafile"], "SSL CA certificate")
        ssl_certfile = validate_file_path(secrets["ssl_certfile"], "SSL certificate")
        ssl_keyfile = validate_file_path(secrets["ssl_keyfile"], "SSL key")

        if ssl_cafile:
            client_config["ssl_cafile"] = ssl_cafile
        if ssl_certfile:
            client_config["ssl_certfile"] = ssl_certfile
        if ssl_keyfile:
            client_config["ssl_keyfile"] = ssl_keyfile
        if secrets["ssl_password"]:
            client_config["ssl_password"] = secrets["ssl_password"]

        # Enforce SSL certificate verification
        client_config["ssl_check_hostname"] = True

    # Log connection attempt without sensitive data
    logger.info(
        "Connecting to Kafka cluster at %s with protocol %s",
        validated_servers,
        security_protocol,
    )

    try:
        admin_client = KafkaAdminClient(**client_config)
        logger.info("Successfully connected to Kafka cluster.")
        return admin_client
    except KafkaError as e:
        # Do not log the full exception which might contain credentials
        logger.error("Failed to connect to Kafka cluster: %s", type(e).__name__)
        raise


def create_topics(
    admin_client: KafkaAdminClient,
    topics: List[Dict[str, Any]],
) -> None:
    """Create one or more Kafka topics with validated configurations."""
    new_topics = []

    for topic_spec in topics:
        name = validate_topic_name(topic_spec["name"])
        partitions = validate_partitions(topic_spec.get("partitions", 3))
        replication_factor = validate_replication_factor(
            topic_spec.get("replication_factor", 3)
        )
        config = validate_topic_config(topic_spec.get("config", {}))

        new_topic = NewTopic(
            name=name,
            num_partitions=partitions,
            replication_factor=replication_factor,
            topic_configs=config,
        )
        new_topics.append(new_topic)
        logger.info(
            "Preparing to create topic '%s' with %d partitions, "
            "replication factor %d",
            name,
            partitions,
            replication_factor,
        )

    if not new_topics:
        logger.warning("No valid topics to create.")
        return

    try:
        result = admin_client.create_topics(new_topics=new_topics, validate_only=False)
        logger.info("Topic creation request submitted successfully.")

        # Process results
        for topic_name, future in result.topic_errors.items() if hasattr(result, 'topic_errors') else []:
            error_code, error_message = future
            if error_code == 0:
                logger.info("Topic '%s' created successfully.", topic_name)
            else:
                logger.error(
                    "Failed to create topic '%s': error_code=%d, message=%s",
                    topic_name,
                    error_code,
                    error_message,
                )

    except TopicAlreadyExistsError as e:
        logger.error("One or more topics already exist: %s", e)
        raise
    except InvalidReplicationFactorError as e:
        logger.error("Invalid replication factor: %s", e)
        raise
    except KafkaError as e:
        logger.error("Failed to create topics: %s", type(e).__name__)
        raise


def delete_topics(
    admin_client: KafkaAdminClient,
    topic_names: List[str],
) -> None:
    """Delete one or more Kafka topics."""
    validated_names = [validate_topic_name(name) for name in topic_names]

    logger.info("Preparing to delete topics: %s", validated_names)

    try:
        admin_client.delete_topics(topics=validated_names)
        logger.info("Topic deletion request submitted for: %s", validated_names)
    except UnknownTopicOrPartitionError as e:
        logger.error("One or more topics do not exist: %s", e)
        raise
    except KafkaError as e:
        logger.error("Failed to delete topics: %s", type(e).__name__)
        raise


def add_partitions(
    admin_client: KafkaAdminClient,
    topic_name: str,
    total_partitions: int,
) -> None:
    """Increase the number of partitions for a topic."""
    validated_name = validate_topic_name(topic_name)
    validated_partitions = validate_partitions(total_partitions)

    logger.info(
        "Increasing partitions for topic '%s' to %d",
        validated_name,
        validated_partitions,
    )

    try:
        partition_spec = {validated_name: NewPartitions(total_count=validated_partitions)}
        admin_client.create_partitions(partition_spec)
        logger.info(
            "Partition increase request submitted for topic '%s' to %d partitions.",
            validated_name,
            validated_partitions,
        )
    except KafkaError as e:
        logger.error(
            "Failed to add partitions to topic '%s': %s",
            validated_name,
            type(e).__name__,
        )
        raise


def describe_topics(
    admin_client: KafkaAdminClient,
    topic_names: List[str],
) -> None:
    """Describe one or more Kafka topics."""
    validated_names = [validate_topic_name(name) for name in topic_names]

    try:
        topic_metadata = admin_client.describe_topics(validated_names)
        for topic_info in topic_metadata:
            topic = topic_info.get("topic", "unknown")
            partitions = topic_info.get("partitions", [])
            logger.info("Topic: %s", topic)
            logger.info("  Partitions: %d", len(partitions))
            for partition in partitions:
                logger.info(
                    "    Partition %d: leader=%s, replicas=%s, isr=%s",
                    partition.get("partition", -1),
                    partition.get("leader", "unknown"),
                    partition.get("replicas", []),
                    partition.get("isr", []),
                )
    except KafkaError as e:
        logger.error("Failed to describe topics: %s", type(e).__name__)
        raise


def list_topics(admin_client: KafkaAdminClient) -> List[str]:
    """List all topics in the Kafka cluster."""
    try:
        topics = admin_client.list_topics()
        # Filter out internal topics
        user_topics = [t for t in topics if not t.startswith("__")]
        logger.info("Found %d user topics:", len(user_topics))
        for topic in sorted(user_topics):
            logger.info("  - %s", topic)
        return user_topics
    except KafkaError as e:
        logger.error("Failed to list topics: %s", type(e).__name__)
        raise


def alter_topic_config(
    admin_client: KafkaAdminClient,
    topic_name: str,
    config: Dict[str, str],
) -> None:
    """Alter configuration for a Kafka topic."""
    validated_name = validate_topic_name(topic_name)
    validated_config = validate_topic_config(config)

    logger.info(
        "Altering configuration for topic '%s': keys=%s",
        validated_name,
        list(validated_config.keys()),
    )

    try:
        resource = ConfigResource(
            ConfigResourceType.TOPIC,
            validated_name,
            configs=validated_config,
        )
        admin_client.alter_configs([resource])
        logger.info(
            "Configuration alteration request submitted for topic '%s'.",
            validated_name,
        )
    except KafkaError as e:
        logger.error(
            "Failed to alter configuration for topic '%s': %s",
            validated_name,
            type(e).__name__,
        )
        raise


def describe_topic_config(
    admin_client: KafkaAdminClient,
    topic_name: str,
) -> None:
    """Describe configuration for a Kafka topic."""
    validated_name = validate_topic_name(topic_name)

    try:
        resource = ConfigResource(ConfigResourceType.TOPIC, validated_name)
        result = admin_client.describe_configs([resource])
        logger.info("Configuration for topic '%s':", validated_name)
        for config_resource, config_entries in result.items():
            for key, value in config_entries.items():
                logger.info("  %s = %s", key, value)
    except KafkaError as e:
        logger.error(
            "Failed to describe configuration for topic '%s': %s",
            validated_name,
            type(e).__name__,
        )
        raise


def parse_config_string(config_str: str) -> Dict[str, str]:
    """Parse a configuration string in the format 'key1=value1,key2=value2'."""
    config = {}
    if not config_str:
        return config

    for pair in config_str.split(","):
        pair = pair.strip()
        if "=" not in pair:
            raise InputValidationError(
                f"Invalid config format: '{pair}'. Expected 'key=value'."
            )
        key, value = pair.split("=", 1)
        key = key.strip()
        value = value.strip()
        if not key:
            raise InputValidationError("Configuration key cannot be empty.")
        config[key] = value

    return config


def load_config_file(file_path: str) -> Dict[str, Any]:
    """Load topic configuration from a JSON file with validation."""
    validated_path = validate_file_path(file_path, "Configuration")
    if validated_path is None:
        raise InputValidationError(f"Configuration file not found: {file_path}")

    try:
        with open(validated_path, "r") as f:
            content = f.read(1024 * 1024)  # Limit to 1MB
            data = json.loads(content)

        if not isinstance(data, dict):
            raise InputValidationError("Configuration file must contain a JSON object.")

        return data
    except json.JSONDecodeError as e:
        raise InputValidationError(f"Invalid JSON in configuration file: {e}")
    except OSError as e:
        raise InputValidationError(f"Cannot read configuration file: {e}")


